// Format rows for LLM clustering. Keep last 14 days only.
const pages = $json.results || [];
const cutoff = new Date(Date.now() - 14 * 86400000);

function extract(prop) {
  if (!prop) return '';
  if (prop.title) return prop.title.map(t => t.plain_text || '').join('');
  if (prop.rich_text) return prop.rich_text.map(t => t.plain_text || '').join('');
  return '';
}

const rows = [];
for (const p of pages) {
  const created = new Date(p.created_time);
  if (created < cutoff) continue;
  const props = p.properties || {};
  rows.push({
    id: p.id,
    url: p.url,
    created: p.created_time,
    task: extract(props.Task),
    source: extract(props.Source),
    project: (props.Project && props.Project.select && props.Project.select.name) || null,
    notes_excerpt: extract(props.Notes).slice(0, 600),
  });
}

if (rows.length < 2) {
  return [{ json: { skip: true, reason: 'fewer than 2 rows to dedupe', row_count: rows.length } }];
}

const formatted = rows.map((r, i) => `[${i}] id=${r.id} created=${r.created.slice(0,10)} project=${r.project || '-'}\n  task: ${r.task}\n  source: ${r.source}\n  notes: ${r.notes_excerpt.slice(0, 400)}`).join('\n\n');

const prompt = `You are clustering action item rows that refer to the SAME underlying real-world action item, even when captured from different channels (meeting, email, Slack).

ROWS (${rows.length}):

${formatted}

---

Group rows that represent the SAME action item. A group must have 2+ rows. Examples of valid groupings:
- A meeting AI "Send Bassem the deck" + an email "Following up on the deck for Bassem" = same item, different channels
- A Slack ask "Sales User can you intro me to Executive" + a meeting AI "Sales User to intro X to Executive" = same item, different channels
- A meeting AI "Reschedule the Bassem meeting" + an email "Proposing new time for Bassem" = same item

Do NOT group:
- Different action items that share a person or topic
- Different commitments to the same person ("send deck" vs "send proposal")
- Rows about different meetings/events even if attendees overlap
- Different reschedule/availability requests from DIFFERENT senders (Barret rescheduling is NOT the same as Tony rescheduling, even though both are "reschedule a call with Sales User")
- Different intro/connection requests between different parties
- Generic category overlap (both are "reschedule" or both are "meeting") is NOT enough — the SPECIFIC underlying action must match including the SAME other party

For each group, pick the OLDEST row (lowest created_time) as the primary. Other rows are duplicates that should be merged into the primary.

Return ONLY JSON. If no groups found, return empty array:
{
  "groups": [
    {
      "primary_id": "<oldest row id>",
      "duplicate_ids": ["<row id>", "<row id>"],
      "confidence": 0.0-1.0,
      "reason": "<one sentence>"
    }
  ]
}

Only emit groups with confidence >= 0.9. Be conservative — false-positive merges are worse than missed merges.`;

return [{ json: { rows, prompt } }];

// Parse LLM output, validate with entity-overlap guardrail, emit merge items.

const llm = $input.first().json;
const rows = $('Format + prompt').first().json.rows || [];
const rowsById = Object.fromEntries(rows.map(r => [r.id, r]));

// Generic / category words that DO NOT count as specific entities.
const GENERIC = new Set([
  // people Sales User talks to constantly — not useful for distinguishing rows
  'Sales User','Sales User','Executive','Stakeholder','common-name',
  // template / structural words from the Notes formatting
  'ais','source','summary','from','to','channel','attendees','date','action','items','notes','task','tasks','gmail','message','id','ts','permalink','iid','paired','recall','notetaker','zoom','google','meet','teams','slack','calendar','calendar_event','event','url','href','snippet','section',
  // action verbs (Notes content)
  'meeting','call','email','thread','chat','intro','introduction','introduce','connect','reschedule','setup','schedule','arrange','send','sent','draft','confirm','review','check','update','followup','follow','plan','plans','propose','proposed','availability','responding','respond','deliverable','investigate','resolve','identify','develop','brief','prepare','attend','share','provide','create','build','make','run','start','finish','complete','sign','sign-off','approve','reject','consider','evaluate','explore','discuss','establish','define','draft','outline','consolidate','reconcile','coordinate','manage','handle','sort','triage','submit','file','log','post','mention','flag','tag','assign','reassign','delegate',
  // generic project / company / team words
  'project','company','team','staff','people','person','firm','group','board','member','members','client','customer','partner','vendor','contractor','employee',
  // time / date words
  'today','tomorrow','yesterday','morning','afternoon','evening','week','day','month','year','noon','am','pm','est','pst','pdt','edt','eastern','western','pacific','time','timezone','tz',
  // domain category words
  'data','center','centers','dc','hyperscaler','solar','battery','energy','power','industry',
  // sample_company / company self-references
  'sample_company','zero','rfi','0rfi','rollup','corp','corporate','dev','development','operations','content','personal',
  // placeholder / Speaker labels
  'speaker','speaker_a','speaker_b','speaker_c','unassigned','tbd','none','unknown',
  // months / days
  'jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec','january','february','march','april','june','july','august','september','october','november','december','mon','tue','wed','thu','fri','sat','sun','monday','tuesday','wednesday','thursday','friday','saturday','sunday',
]);

function extractEntities(row) {
  const blob = `${row.task || ''} ${row.notes_excerpt || ''} ${row.source || ''}`;
  const set = new Set();
  // Proper nouns: capitalized tokens of length >= 3 — typically named entities
  for (const m of blob.matchAll(/\b([A-Z][a-zA-Z]{2,})\b/g)) {
    const tok = m[1].toLowerCase();
    if (!GENERIC.has(tok)) set.add(tok);
  }
  // Email domain hosts (@schneider.com → schneider)
  for (const m of blob.matchAll(/@([a-z0-9-]+)\./gi)) {
    const tok = m[1].toLowerCase();
    if (!GENERIC.has(tok) && tok.length >= 3) set.add(tok);
  }
  // Explicit "From:" line extraction (case-insensitive; Slack sender often lowercase like "From: barret")
  for (const m of blob.matchAll(/^\s*From:\s*([A-Za-z][A-Za-z0-9_-]{1,40})/gim)) {
    const tok = m[1].toLowerCase();
    if (!GENERIC.has(tok) && tok.length >= 3) set.add(tok);
  }
  // "Channel:" line extraction
  for (const m of blob.matchAll(/^\s*Channel:\s*([A-Za-z][A-Za-z0-9_-]{1,40})/gim)) {
    const tok = m[1].toLowerCase();
    if (!GENERIC.has(tok) && tok.length >= 3) set.add(tok);
  }
  return set;
}

function intersect(a, b) {
  return [...a].filter(x => b.has(x));
}

let parsed = null;
try {
  const text = (llm.content || []).map(c => c.text || '').join('');
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('no JSON');
  parsed = JSON.parse(m[0]);
} catch (e) {
  return [];
}

const rawGroups = (parsed.groups || []).filter(g => g.confidence >= 0.9 && g.primary_id && Array.isArray(g.duplicate_ids) && g.duplicate_ids.length > 0);

const out = [];
const rejected = [];
for (const g of rawGroups) {
  const primary = rowsById[g.primary_id];
  if (!primary) { rejected.push({ group: g, reason: 'primary row missing from cache' }); continue; }
  const dups = g.duplicate_ids.map(id => rowsById[id]).filter(Boolean);
  if (dups.length === 0) { rejected.push({ group: g, reason: 'all duplicate rows missing' }); continue; }

  // ENTITY GUARDRAIL: every dup must share ≥1 specific entity with primary
  const primaryEntities = extractEntities(primary);
  let allDupsOverlap = true;
  const overlapDebug = [];
  for (const dup of dups) {
    const dupEntities = extractEntities(dup);
    const overlap = intersect(primaryEntities, dupEntities);
    overlapDebug.push({ dup_id: dup.id, primary_entities: [...primaryEntities], dup_entities: [...dupEntities], overlap });
    if (overlap.length === 0) { allDupsOverlap = false; break; }
  }

  if (!allDupsOverlap) {
    rejected.push({ group: g, reason: 'no specific entity overlap', debug: overlapDebug });
    continue;
  }

  const mergeNote = `\n\n--- merged from ${dups.length} duplicate row(s) on ${new Date().toISOString().slice(0,10)} (LLM conf=${g.confidence}) ---\n`;
  const dupSourceLines = dups.map(d => `- ${d.source} | ${d.url}`).join('\n');
  const newNotes = `${primary.notes_excerpt}${mergeNote}${dupSourceLines}\nReason: ${g.reason || ''}`.slice(0, 1990);

  out.push({ json: { primary_id: g.primary_id, dup_ids: g.duplicate_ids, dup_rows: dups, confidence: g.confidence, reason: g.reason, new_notes: newNotes, overlap_debug: overlapDebug } });
}

// Surface rejections in workflow for transparency (Aggregate will pick them up)
this.helpers && console.log('Dedupe rejections:', JSON.stringify(rejected).slice(0, 1000));
return out;

// Emit one archive item per duplicate ID across all groups.
const out = [];
for (const item of $input.all()) {
  const plan = item.json;
  for (const id of (plan.dup_ids || [])) {
    out.push({ json: { archive_id: id, merged_into: plan.primary_id, reason: plan.reason || '', new_notes: plan.new_notes } });
  }
}
return out;

// Aggregate stats from both branches.
let primaryUpdates = [];
let archives = [];
try { primaryUpdates = $('Update primary notes').all().map(i => i.json).filter(j => j && j.object === 'page'); } catch (e) {}
try { archives = $('Archive duplicate').all().map(i => i.json).filter(j => j && j.object === 'page'); } catch (e) {}

const plansText = (($('Anthropic cluster').first().json.content || []).map(c => c.text || '').join(''));
let parsedPlans = null;
try {
  const m = plansText.match(/\{[\s\S]*\}/);
  if (m) parsedPlans = JSON.parse(m[0]);
} catch (e) {}

return {
  summary: {
    groups_identified: (parsedPlans && parsedPlans.groups || []).length,
    primaries_updated: primaryUpdates.length,
    duplicates_archived: archives.length,
    generated_at: new Date().toISOString(),
  },
  groups: parsedPlans && parsedPlans.groups || [],
  primaries_updated: primaryUpdates.map(p => ({ id: p.id, url: p.url })),
  duplicates_archived: archives.map(p => ({ id: p.id, url: p.url })),
};
